        // Create an XML parser with HTML settings (which normalize tags)
        Parser xmlParser = Parser.xmlParser();
        // Use HTML settings which should normalize tags (convert to lowercase)
        ParseSettings htmlSettings = new ParseSettings(false); // false means case sensitive = false, so normalize case

