import org.jsoup.Jsoup;
import org.jsoup.parser.Parser;
import org.jsoup.parser.ParseSettings;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;

public class TestFix {
    public static void main(String[] args) {
        // Test the issue: XML parser normalizes end tag names when configured with HTML settings
        // Input: "<div>test</DIV><p></p>"
        // Expected: "<div>\n test\n</div>\n<p></p>" with p element as sibling of div

        System.out.println("Testing the fix for XML parser tag normalization with HTML settings...");

        // Create an XML parser and then set it to use HTML settings
        Parser xmlParser = Parser.xmlParser();  
        ParseSettings htmlSettings = ParseSettings.htmlDefault; // HTML default settings normalize case

        String input = "<div>test</DIV><p></p>";
        System.out.println("Input: " + input);

        // Parse with XML parser using HTML settings
        Document doc = Jsoup.parse(input, xmlParser.settings(htmlSettings));

        String output = doc.toString().trim();
        System.out.println("Output: " + output);

        // Check if div and p are siblings (same parent) - this is key to the fix
        Element div = doc.selectFirst("div");
        Element p = doc.selectFirst("p");

        if (div != null && p != null) {
            if (div.parent() != null && p.parent() != null && div.parent().equals(p.parent())) {
                System.out.println("SUCCESS: div and p are siblings! This means the </DIV> tag properly closed the <div> tag.");
                System.out.println("- div parent: " + (div.parent() != null ? div.parent().nodeName() : "null"));
                System.out.println("- p parent: " + (p.parent() != null ? p.parent().nodeName() : "null"));
            } else {
                System.out.println("FAILURE: div and p are not siblings!");
                System.out.println("- div parent: " + (div.parent() != null ? div.parent().nodeName() : "null"));
                System.out.println("- p parent: " + (p.parent() != null ? p.parent().nodeName() : "null"));

                // Before fix: </DIV> wouldn't close <div>, so <p> would be inside div
                if (div.equals(p.parent())) {
                    System.out.println("- The <p> element is a child of the <div> element, indicating the fix didn't work.");
                }
            }
        } else {
            System.out.println("FAILURE: Could not find div or p elements!");
        }

        // Additional verification: check if the DIV was properly closed
        System.out.println("Number of div elements: " + doc.select("div").size());
        System.out.println("Number of p elements: " + doc.select("p").size());
    }
}

